CREATE TABLE IF NOT EXISTS "pages" ("id" integer primary key autoincrement not null, "categorie" varchar not null, "title" varchar not null, "name" varchar not null, "content" text, "created_at" datetime, "updated_at" datetime);
INSERT INTO pages VALUES(1,'asso','Présentation','pres','<div class="grid-layout" data-cols="3" style="--cols: repeat(3, minmax(0, 1fr));" data-from-breakpoint="lg"><div class="grid-layout-col" data-col-span="1" style="--col-span: span 1 / span 1;"><p></p></div><div class="grid-layout-col" data-col-span="1" style="--col-span: span 1 / span 1;"><p><img src="http://localhost:8000/storage/LEjsU6yxBBOMPgv4PNmWOlEmzyXKACZO0MQnPKZM.png" data-id="LEjsU6yxBBOMPgv4PNmWOlEmzyXKACZO0MQnPKZM.png"></p></div><div class="grid-layout-col" data-col-span="1" style="--col-span: span 1 / span 1;"><p></p></div></div><p>Notre projet est de mettre à disposition des citoyens des espaces pour apprendre à jardiner, produire une alimentation saine ou se reconnecter à la nature, du matériel, et un local pour se réunir, cuisiner ou bricoler. Ce lieu se veut un lieu d’échanges, de partage de savoir-faire, convivial, avec une programmation d’animations diverses et d’événements rythmée par les saisons.</p><p>L&#039;essence de Labo Binette est de créer une dynamique collective, qui implique les différents partenaires. Les bénéficiaires participent activement par le biais de commissions et de réunions de concertation.</p><p>Nous sommes devenus Espaces de Vie Sociale en juillet 2022, ce qui nous conforte dans notre vocation de renforcer les liens sociaux, familiaux et les solidarités de voisinage, à coordonner et à encourager les initiatives favorisant la vie collective et l’engagement des usagers.</p><h2>Notre mission<strong> :</strong></h2><ul><li><p>Favoriser le lien social autour d&#039;activités éducatives et culturelles ;</p></li><li><p>Favoriser l&#039;accès aux savoirs et savoir-faire en matière de production vivrière et culinaire et ainsi développer l&#039;autonomie alimentaire ;</p></li><li><p>Permettre la sensibilisation à l’agroécologie, l&#039;éducation à l&#039;environnement et à la citoyenneté ;</p></li><li><p>Expérimenter des pratiques coopératives écologiques et éco-citoyennes.</p></li></ul><h2>A terme, les actions que nous souhaitons proposer sont<strong> :</strong></h2><ul><li><p>Mise en place d&#039;un jardin communautaire, avec participation technique d’un maraîcher établi sur la parcelle</p></li><li><p>Mise à disposition de parcelles familiales pour jardiner</p></li><li><p>Organisation de sorties et animations de sensibilisation (biodiversité, jardinage, cuisine, bricolage...)</p></li><li><p>Mise à disposition d&#039;une cuisine partagée et de salles d&#039;activités</p></li><li><p>Organisation d&#039;événements conviviaux</p></li><li><p>Déploiement d&#039;un café associatif pour valoriser les produits locaux, qui pourra démarrer sur un mode éphémère</p></li></ul><h2><strong>L</strong>e lieu et le projet d’aménagement <strong>:</strong></h2><p>La commune de Labarthe-sur-Lèze met à la disposition du projet une parcelle communale de 3 ha localisée dans une boucle de la Lèze, qui n’est plus cultivée depuis une quinzaine d’années. La commune et Labo Binette ont travaillé avec le CAUE pour établir les grands principes d’aménagement de la parcelle résumés dans le plan qui suit</p>','2026-03-30 09:15:20','2026-03-31 10:39:39');
INSERT INTO pages VALUES(2,'ecolieu','Des espaces pédagogique','peda','<p>L&#039;espace pédagogique est un mandala et des carrés potagers.</p><p></p><p>Il est possible de se promener à la découverte des carrés potager plantés par les enfants le mercredi ou les écoles qui viennent sur le site, ou de découvrir les plantes du jardin en mandala : plantes aromatiques, légumes perpétuels, plantes mellifères, etc...</p><p></p><p></p><p>N’hésitez pas à venir le découvrir au détour d’une balade !</p>','2026-03-31 14:30:38','2026-03-31 14:30:38');
INSERT INTO pages VALUES(3,'ecolieu','Un jardin collectif','jardinco','<p>Le jardin collectif est une parcelle cultivée par un groupe de jardinier</p><p></p><p>Le but étant d&#039;apprendre ensemble et de partager une récolte</p><p></p><p>Plusieurs fois par semaine le groupe se retrouve pour faire vivre cette parcelle.</p><p></p><p>Ce jardin est un lieu ouvert où il est possible de venir admirer les légumes et les fleurs (tout en respectant les chemins pour se déplacer !)</p>','2026-03-31 14:32:18','2026-03-31 14:32:18');
INSERT INTO pages VALUES(4,'ecollieu','Verger collectif','vergerco','<p>Le verger collectif est un lieu ouvert où tout le monde peut déambuler à la découverte des différentes variétés d’arbres fruitiers présents !</p><p></p><p>Abricotiers, pommiers, poiriers, grenadiers ouvrez l&#039;œil !</p><p></p><p>L’espace de convivialité (pergola et bancs) permet de se poser pour se ressourcer ou pique-niquer</p>','2026-03-31 14:36:31','2026-03-31 14:36:31');
INSERT INTO pages VALUES(5,'ecolieu','Un espace de convivialité','espace','<p></p>','2026-03-31 14:37:24','2026-03-31 14:37:24');
INSERT INTO pages VALUES(6,'ecolieu','Un espace naturel','nature','<p>La préservation et la découverte de la biodiversité locale sont des actions qui nous tiennent à cœur !</p><p>Dans le contexte urbanisé de la périphérie toulousaine, Labo Binette s’insère dans une boucle dessinée par la Lèze, ce qui lui confère un aspect de “presqu&#039;île” dans un écrin de verdure. La Lèze dans sa boucle est en effet insérée dans un écrin de végétation appelé ripisylve. Véritables corridors écologiques, la Lèze et sa ripisylve constituent un couloir aquatique et végétalisé, qui permet à la faune et à la flore locales de se déplacer, se réfugier ou se nourrir.</p><p>Le projet prévoit également la création sur la parcelle d’une prairie semi-naturelle, de mares ou de haies champêtres qui seront autant de milieux diversifiés pour accueillir un maximum de biodiversité. Ces aménagements verront le jour dans les années qui viennent.</p><p></p><p>Avec la participation de Nature En Jeux, association d’éducation à l’environnement partenaire du projet Labo Binette, nous vous proposons dès aujourd’hui d’apprendre à connaître et à protéger la biodiversité locale avec des animateurs nature : sorties de découverte, sentiers pédagogiques ou actions de préservation peuvent vous être proposées !</p>','2026-03-31 14:38:28','2026-03-31 14:38:28');
INSERT INTO pages VALUES(7,'activites','Kibine','kibine','<p>A l’heure actuelle la communauté des jardiniers cultive collectivement depuis mai 2022 une parcelle de 150 m² de potager. Avant de se lancer ils ont décidé de leur organisation et ont fixé un “réglement” du jardin. Ils s’organisent pour les achats de semences, de plants, d’amendement et participent à l’amortissement des outils. Ils listent chaque mois les tâches à accomplir et se relaient ou jardinent collectivement selon les disponibilités de chacun. Un bon moyen d’apprendre à jardiner sans se sentir seul !</p><p>Nous vous donnons rendez vous le dimanche matin pour plus de renseignements, c’est le moment de la semaine où vous êtes sûrs de trouver des jardiniers qui s’activent !</p>','2026-03-31 14:50:16','2026-03-31 14:50:35');
INSERT INTO pages VALUES(8,'activites','Kibutine','kibutine','<p>Enfin nous avons un rucher collectif. Sur le même principe que pour le jardin collectif (Kibine), c&#039;est un groupe de familles qui gère le rucher : installation, achat ou récupération des essaims, suivis réguliers, récolte et partage du miel produit. Tous novices, ils se forment au fil des saisons grâce à des bénévoles apiculteurs amateurs. L&#039;activité à démarré en mars 2023, nous allons vers notre première récolte : c&#039;est très enthousiasmant !</p><p>N’hésitez pas à nous contacter si cette activité vous intéresse !</p>','2026-03-31 14:51:45','2026-03-31 14:51:45');
INSERT INTO pages VALUES(9,'activites','Kiplante','kiplante','<p>Nous avons également une communauté qui s’occupe du verger collectif. Ils programment les plantations, l’entretien, apprennent à greffer, à tailler les arbres, etc. Une 1ère parcelle a été plantée en 2 saisons, l’hiver 2020 et l’hiver 2021, et un grand verger est également prévu au sud de la parcelle centrale de la boucle de la Lèze.</p>','2026-03-31 14:52:37','2026-03-31 14:52:37');
INSERT INTO pages VALUES(10,'activites','Kipicore','kipicore','<p>En construction</p>','2026-03-31 14:53:54','2026-03-31 14:53:54');
